	private JoinRegionCandidate canonicalizeBindingShape(int groupId, JoinRegionCandidate candidate) {
		BindingMask expectedPossible = possibleBindingsByGroup.get(groupId);
		BindingMask expectedAssured = assuredBindingsByGroup.get(groupId);
		if (expectedPossible == null) {
			possibleBindingsByGroup.set(groupId, candidate.possibleBindings());
			assuredBindingsByGroup.set(groupId, candidate.assuredBindings());
			return candidate;
		}
		if (!expectedPossible.equals(candidate.possibleBindings())
				|| !expectedAssured.equals(candidate.assuredBindings())) {
			throw new IllegalArgumentException("candidate binding shape differs from scoped group " + groupId);
		}
		return candidate.withBindingShape(expectedPossible, expectedAssured);
	}

	private boolean dominates(JoinRegionCandidate left, JoinRegionCandidate right) {
		if (!left.group().equals(right.group()) || !noMoreParameterized(left.provided(), right.provided())
				|| !providedPropertiesSatisfy(left.provided(), right.provided())) {
			return false;
		}
		return costOrdering.dominates(rank(left), rank(right));
	}

	private boolean equivalentAndCanonical(JoinRegionCandidate left, JoinRegionCandidate right) {
		if (!left.group().equals(right.group())
				|| !left.provided().parameterBindings().equals(right.provided().parameterBindings())
				|| !providedPropertiesSatisfy(left.provided(), right.provided())
				|| !providedPropertiesSatisfy(right.provided(), left.provided())) {
			return false;
		}
		RankedCost leftCost = rank(left);
		RankedCost rightCost = rank(right);
		return leftCost.resources().equals(rightCost.resources())
				&& left.operator().compareTo(right.operator()) <= 0;
	}

	private RankedCost rank(JoinRegionCandidate candidate) {
		return costOrdering.rank(candidate.cost(), candidate.risk(), candidate.operator());
	}

	private int compare(JoinRegionCandidate left, JoinRegionCandidate right) {
		return costOrdering.compare(rank(left), rank(right));
	}

